contracts/Governance.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";

interface IPropertyToken {
    function getVotingPower(uint256 propertyId, address voter) external view returns (uint256);
    function balanceOf(address account, uint256 id) external view returns (uint256);
    function totalSupply(uint256 id) external view returns (uint256);
    function getTotalWeightedVotingPower(uint256 propertyId) external view returns (uint256);
}

/**
 * @title RevitaHub Governance
 * @notice DAO voting with phase-weighted voting power
 * @dev County holders get 1.5x, State 1.25x, National 1.0x, International 0.75x
 */
contract Governance is AccessControl, ReentrancyGuard {
    using ECDSA for bytes32;
    using MessageHashUtils for bytes32;

    bytes32 public constant PROPOSER_ROLE = keccak256("PROPOSER_ROLE");
    bytes32 public constant EXECUTOR_ROLE = keccak256("EXECUTOR_ROLE");
    bytes32 public constant RELAYER_ROLE = keccak256("RELAYER_ROLE");

    IPropertyToken public propertyToken;

    // Domain separator for EIP-712 signatures
    bytes32 public immutable DOMAIN_SEPARATOR;
    bytes32 public constant VOTE_TYPEHASH = keccak256("Vote(uint256 proposalId,uint8 support,address voter,uint256 nonce,uint256 deadline)");

    // Nonces for replay protection
    mapping(address => uint256) public nonces;

    // Proposal types
    enum ProposalType { 
        PropertyDevelopment,  // How to develop a property
        TreasuryAllocation,   // How to spend treasury funds
        ParameterChange,      // Change platform parameters
        Emergency             // Emergency actions
    }

    // Proposal status
    enum ProposalStatus {
        Pending,
        Active,
        Succeeded,
        Defeated,
        Executed,
        Cancelled
    }

    // Proposal structure
    struct Proposal {
        uint256 id;
        uint256 propertyId;
        address proposer;
        ProposalType proposalType;
        string title;
        string description;
        string ipfsHash;
        uint256 votesFor;
        uint256 votesAgainst;
        uint256 votesAbstain;
        uint256 startTime;
        uint256 endTime;
        uint256 quorumRequired;
        ProposalStatus status;
        bytes executionData;
    }

    // Vote record
    struct Vote {
        bool hasVoted;
        uint8 support; // 0 = against, 1 = for, 2 = abstain
        uint256 weight;
    }

    // Quorum requirements (basis points of total voting power)
    uint256 public constant QUORUM_PROPERTY = 2000;   // 20% for property decisions
    uint256 public constant QUORUM_TREASURY = 3000;   // 30% for treasury
    uint256 public constant QUORUM_PARAMETER = 2500;  // 25% for parameters
    uint256 public constant QUORUM_EMERGENCY = 5000;  // 50% for emergency

    // Voting period
    uint256 public votingPeriod = 7 days;

    // Vote-to-earn bonus APR (in basis points, e.g., 50 = 0.5%)
    uint256 public voteToEarnBonus = 50;

    // Storage
    mapping(uint256 => Proposal) public proposals;
    uint256 public proposalCount;

    mapping(uint256 => mapping(address => Vote)) public votes;
    mapping(uint256 => uint256) public totalVotingPower; // Total voting power at proposal creation

    // Vote-to-earn tracking
    mapping(address => uint256) public voterParticipationCount;
    mapping(address => uint256) public lastVoteTimestamp;

    // ============ Community Polls (Non-Binding Gauges) ============

    // Poll status
    enum PollStatus {
        Active,
        Ended,
        ConvertedToProposal
    }

    // Poll structure for community demand gauges
    struct Poll {
        uint256 id;
        uint256 propertyId;         // 0 for platform-wide polls
        address creator;
        string question;
        string description;
        string ipfsHash;
        uint256 votesFor;
        uint256 votesAgainst;
        uint256 startTime;
        uint256 endTime;
        PollStatus status;
        uint256 linkedProposalId;   // If converted to proposal
    }

    // Poll vote record
    struct PollVote {
        bool hasVoted;
        bool support;
    }

    // Poll storage
    mapping(uint256 => Poll) public polls;
    uint256 public pollCount;
    mapping(uint256 => mapping(address => PollVote)) public pollVotes;
    mapping(uint256 => uint256) public pollParticipants; // Total unique voters per poll

    // Poll-to-proposal threshold (30% support in basis points)
    uint256 public constant POLL_PROPOSAL_THRESHOLD = 3000;

    // Poll quorum bonus (5% reduction when poll-backed)
    uint256 public constant POLL_QUORUM_BONUS = 500;

    // ============ SimCity-Style Demand Meters ============

    // Cumulative vote weight per proposal type (tracks community demand signals)
    mapping(ProposalType => uint256) public typeDemandWeights;

    // Demand snapshots in BPS (e.g., 7500 = 75% of total votes for this type)
    mapping(ProposalType => uint256) public demandSnapshots;

    // Total demand weight across all types (for percentage calculation)
    uint256 public totalDemandWeight;

    // Demand-driven quorum boost threshold (50% demand = -5% quorum)
    uint256 public constant DEMAND_QUORUM_BOOST_THRESHOLD = 5000;
    uint256 public constant DEMAND_QUORUM_BOOST = 500;

    // Events
    event ProposalCreated(
        uint256 indexed proposalId,
        uint256 indexed propertyId,
        address proposer,
        ProposalType proposalType,
        string title
    );
    event VoteCast(
        uint256 indexed proposalId,
        address indexed voter,
        uint8 support,
        uint256 weight
    );
    event ProposalExecuted(uint256 indexed proposalId);
    event ProposalCancelled(uint256 indexed proposalId);
    event VotingPeriodUpdated(uint256 newPeriod);
    event VoteToEarnBonusUpdated(uint256 newBonus);

    // Poll events
    event PollCreated(
        uint256 indexed pollId,
        uint256 indexed propertyId,
        address creator,
        string question
    );
    event PollVoteCast(
        uint256 indexed pollId,
        address indexed voter,
        bool support
    );
    event PollEnded(uint256 indexed pollId, uint256 votesFor, uint256 votesAgainst);
    event PollConvertedToProposal(uint256 indexed pollId, uint256 indexed proposalId);

    event OffChainVoteCast(
        uint256 indexed proposalId,
        address indexed voter,
        uint8 support,
        uint256 weight,
        address relayer
    );

    // Demand meter events
    event DemandUpdated(
        ProposalType indexed proposalType,
        uint256 demandWeight,
        uint256 demandBps
    );
    event DemandSnapshotTaken(
        uint256[4] demandBars
    );

    constructor(address _propertyToken) {
        propertyToken = IPropertyToken(_propertyToken);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(PROPOSER_ROLE, msg.sender);
        _grantRole(EXECUTOR_ROLE, msg.sender);
        _grantRole(RELAYER_ROLE, msg.sender);

        // Set up EIP-712 domain separator
        DOMAIN_SEPARATOR = keccak256(
            abi.encode(
                keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"),
                keccak256(bytes("RevitaHub Governance")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    /**
     * @notice Create a new proposal
     * @param propertyId Property ID (0 for platform-wide proposals)
     * @param proposalType Type of proposal
     * @param title Proposal title
     * @param description Proposal description
     * @param ipfsHash IPFS hash for detailed documentation
     * @param executionData Encoded execution data
     */
    function createProposal(
        uint256 propertyId,
        ProposalType proposalType,
        string memory title,
        string memory description,
        string memory ipfsHash,
        bytes memory executionData
    ) external onlyRole(PROPOSER_ROLE) returns (uint256) {
        // Require token holdings to create proposal
        require(
            propertyToken.getVotingPower(propertyId, msg.sender) > 0,
            "Must hold tokens to propose"
        );

        uint256 proposalId = proposalCount++;
        uint256 quorum = _getQuorum(proposalType);

        // Snapshot total WEIGHTED voting power at proposal creation
        // Uses the same weighting as individual votes for consistency
        uint256 snapshotVotingPower = propertyToken.getTotalWeightedVotingPower(propertyId);
        require(snapshotVotingPower > 0, "No voting power exists for this property");
        totalVotingPower[proposalId] = snapshotVotingPower;

        proposals[proposalId] = Proposal({
            id: proposalId,
            propertyId: propertyId,
            proposer: msg.sender,
            proposalType: proposalType,
            title: title,
            description: description,
            ipfsHash: ipfsHash,
            votesFor: 0,
            votesAgainst: 0,
            votesAbstain: 0,
            startTime: block.timestamp,
            endTime: block.timestamp + votingPeriod,
            quorumRequired: quorum,
            status: ProposalStatus.Active,
            executionData: executionData
        });

        emit ProposalCreated(proposalId, propertyId, msg.sender, proposalType, title);
        return proposalId;
    }

    /**
     * @notice Cast a vote on a proposal
     * @param proposalId Proposal ID
     * @param support 0 = against, 1 = for, 2 = abstain
     */
    function castVote(uint256 proposalId, uint8 support) external nonReentrant {
        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Active, "Proposal not active");
        require(block.timestamp >= proposal.startTime, "Voting not started");
        require(block.timestamp < proposal.endTime, "Voting ended");
        require(support <= 2, "Invalid vote type");

        Vote storage voterRecord = votes[proposalId][msg.sender];
        require(!voterRecord.hasVoted, "Already voted");

        // Get voting power (phase-weighted)
        uint256 weight = propertyToken.getVotingPower(proposal.propertyId, msg.sender);
        require(weight > 0, "No voting power");

        // Record vote
        voterRecord.hasVoted = true;
        voterRecord.support = support;
        voterRecord.weight = weight;

        // Tally votes
        if (support == 0) {
            proposal.votesAgainst += weight;
        } else if (support == 1) {
            proposal.votesFor += weight;
        } else {
            proposal.votesAbstain += weight;
        }

        // Update vote-to-earn tracking
        voterParticipationCount[msg.sender]++;
        lastVoteTimestamp[msg.sender] = block.timestamp;

        // Update demand meters
        _updateDemandMeters(proposal.proposalType, weight);

        emit VoteCast(proposalId, msg.sender, support, weight);
    }

    /**
     * @notice Cast a vote using off-chain signature (gasless voting)
     * @dev Enables lower-income investors to vote without paying gas
     * @param proposalId Proposal ID
     * @param support 0 = against, 1 = for, 2 = abstain
     * @param voter The address of the voter who signed
     * @param deadline Timestamp after which signature expires
     * @param v ECDSA signature component
     * @param r ECDSA signature component
     * @param s ECDSA signature component
     */
    function castVoteBySignature(
        uint256 proposalId,
        uint8 support,
        address voter,
        uint256 deadline,
        uint8 v,
        bytes32 r,
        bytes32 s
    ) external onlyRole(RELAYER_ROLE) nonReentrant {
        require(block.timestamp <= deadline, "Signature expired");

        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Active, "Proposal not active");
        require(block.timestamp >= proposal.startTime, "Voting not started");
        require(block.timestamp < proposal.endTime, "Voting ended");
        require(support <= 2, "Invalid vote type");

        Vote storage voterRecord = votes[proposalId][voter];
        require(!voterRecord.hasVoted, "Already voted");

        // Verify signature using EIP-712
        uint256 currentNonce = nonces[voter]++;
        bytes32 structHash = keccak256(
            abi.encode(VOTE_TYPEHASH, proposalId, support, voter, currentNonce, deadline)
        );
        bytes32 digest = keccak256(
            abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash)
        );
        address signer = ECDSA.recover(digest, v, r, s);
        require(signer == voter, "Invalid signature");

        // Get voting power (phase-weighted)
        uint256 weight = propertyToken.getVotingPower(proposal.propertyId, voter);
        require(weight > 0, "No voting power");

        // Record vote
        voterRecord.hasVoted = true;
        voterRecord.support = support;
        voterRecord.weight = weight;

        // Tally votes
        if (support == 0) {
            proposal.votesAgainst += weight;
        } else if (support == 1) {
            proposal.votesFor += weight;
        } else {
            proposal.votesAbstain += weight;
        }

        // Update vote-to-earn tracking
        voterParticipationCount[voter]++;
        lastVoteTimestamp[voter] = block.timestamp;

        // Update demand meters
        _updateDemandMeters(proposal.proposalType, weight);

        emit OffChainVoteCast(proposalId, voter, support, weight, msg.sender);
    }

    /**
     * @notice Get current nonce for a voter (for signature creation)
     * @param voter Voter address
     */
    function getNonce(address voter) external view returns (uint256) {
        return nonces[voter];
    }

    /**
     * @notice Finalize a proposal after voting ends
     * @param proposalId Proposal ID
     */
    function finalizeProposal(uint256 proposalId) external {
        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Active, "Proposal not active");
        require(block.timestamp >= proposal.endTime, "Voting not ended");

        uint256 totalVotes = proposal.votesFor + proposal.votesAgainst + proposal.votesAbstain;
        uint256 snapshotSupply = totalVotingPower[proposalId];

        // Calculate participation as basis points of total voting power
        // quorumRequired is in basis points (e.g., 2000 = 20%)
        // Check: (totalVotes * 10000) / snapshotSupply >= quorumRequired
        uint256 participationBps = snapshotSupply > 0 
            ? (totalVotes * 10000) / snapshotSupply 
            : 0;

        bool quorumReached = participationBps >= proposal.quorumRequired;
        bool majority = proposal.votesFor > proposal.votesAgainst;

        if (quorumReached && majority) {
            proposal.status = ProposalStatus.Succeeded;
        } else {
            proposal.status = ProposalStatus.Defeated;
        }
    }

    /**
     * @notice Execute a successful proposal
     * @param proposalId Proposal ID
     */
    function executeProposal(uint256 proposalId) external onlyRole(EXECUTOR_ROLE) nonReentrant {
        Proposal storage proposal = proposals[proposalId];
        require(proposal.status == ProposalStatus.Succeeded, "Proposal not succeeded");

        proposal.status = ProposalStatus.Executed;

        // Execute the proposal (implementation depends on proposal type)
        // In production, this would call the appropriate contract method

        emit ProposalExecuted(proposalId);
    }

    /**
     * @notice Cancel a proposal
     * @param proposalId Proposal ID
     */
    function cancelProposal(uint256 proposalId) external {
        Proposal storage proposal = proposals[proposalId];
        require(
            msg.sender == proposal.proposer || hasRole(DEFAULT_ADMIN_ROLE, msg.sender),
            "Not authorized"
        );
        require(
            proposal.status == ProposalStatus.Active || proposal.status == ProposalStatus.Pending,
            "Cannot cancel"
        );

        proposal.status = ProposalStatus.Cancelled;
        emit ProposalCancelled(proposalId);
    }

    /**
     * @notice Get vote-to-earn bonus eligibility
     * @param voter Voter address
     */
    function getVoteToEarnBonus(address voter) external view returns (uint256) {
        // Bonus applies if voted within last 30 days
        if (block.timestamp - lastVoteTimestamp[voter] <= 30 days) {
            return voteToEarnBonus;
        }
        return 0;
    }

    /**
     * @notice Get proposal details
     * @param proposalId Proposal ID
     */
    function getProposal(uint256 proposalId) external view returns (Proposal memory) {
        return proposals[proposalId];
    }

    /**
     * @notice Get vote details for a voter
     * @param proposalId Proposal ID
     * @param voter Voter address
     */
    function getVote(uint256 proposalId, address voter) external view returns (Vote memory) {
        return votes[proposalId][voter];
    }

    /**
     * @notice Get all active proposals for a property
     * @param propertyId Property ID to filter by
     * @return active Array of active proposals for the property
     */
    function getActiveProposals(uint256 propertyId) external view returns (Proposal[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < proposalCount; i++) {
            if (proposals[i].propertyId == propertyId && proposals[i].status == ProposalStatus.Active) {
                count++;
            }
        }
        Proposal[] memory active = new Proposal[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < proposalCount; i++) {
            if (proposals[i].propertyId == propertyId && proposals[i].status == ProposalStatus.Active) {
                active[idx++] = proposals[i];
            }
        }
        return active;
    }

    /**
     * @notice Get quorum requirement for proposal type (with demand-driven boost)
     */
    function _getQuorum(ProposalType proposalType) internal view returns (uint256) {
        uint256 baseQuorum;
        if (proposalType == ProposalType.PropertyDevelopment) baseQuorum = QUORUM_PROPERTY;
        else if (proposalType == ProposalType.TreasuryAllocation) baseQuorum = QUORUM_TREASURY;
        else if (proposalType == ProposalType.ParameterChange) baseQuorum = QUORUM_PARAMETER;
        else baseQuorum = QUORUM_EMERGENCY;

        // Demand-driven quorum boost: types with >50% demand get -5% quorum
        if (demandSnapshots[proposalType] >= DEMAND_QUORUM_BOOST_THRESHOLD) {
            uint256 boosted = baseQuorum > DEMAND_QUORUM_BOOST ? baseQuorum - DEMAND_QUORUM_BOOST : 1000;
            return boosted < 1000 ? 1000 : boosted; // Minimum 10% quorum
        }
        return baseQuorum;
    }

    /**
     * @notice Update voting period
     * @param newPeriod New voting period in seconds
     */
    function setVotingPeriod(uint256 newPeriod) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newPeriod >= 1 days && newPeriod <= 30 days, "Invalid period");
        votingPeriod = newPeriod;
        emit VotingPeriodUpdated(newPeriod);
    }

    /**
     * @notice Update vote-to-earn bonus
     * @param newBonus New bonus in basis points
     */
    function setVoteToEarnBonus(uint256 newBonus) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newBonus <= 500, "Bonus too high"); // Max 5%
        voteToEarnBonus = newBonus;
        emit VoteToEarnBonusUpdated(newBonus);
    }

    // ============ Community Poll Functions ============

    /**
     * @notice Create a non-binding community poll to gauge demand
     * @dev Polls are lightweight and don't require token holdings
     * @param propertyId Property ID (0 for platform-wide)
     * @param question Poll question
     * @param description Detailed description
     * @param ipfsHash IPFS hash for additional docs
     * @param duration Poll duration in seconds
     */
    function createPoll(
        uint256 propertyId,
        string memory question,
        string memory description,
        string memory ipfsHash,
        uint256 duration
    ) external returns (uint256) {
        require(duration >= 1 days && duration <= 30 days, "Invalid duration");

        uint256 pollId = pollCount++;

        polls[pollId] = Poll({
            id: pollId,
            propertyId: propertyId,
            creator: msg.sender,
            question: question,
            description: description,
            ipfsHash: ipfsHash,
            votesFor: 0,
            votesAgainst: 0,
            startTime: block.timestamp,
            endTime: block.timestamp + duration,
            status: PollStatus.Active,
            linkedProposalId: 0
        });

        emit PollCreated(pollId, propertyId, msg.sender, question);
        return pollId;
    }

    /**
     * @notice Vote on a community poll (no gas subsidy needed - lightweight)
     * @param pollId Poll ID
     * @param support True = support, False = oppose
     */
    function votePoll(uint256 pollId, bool support) external {
        Poll storage poll = polls[pollId];
        require(poll.status == PollStatus.Active, "Poll not active");
        require(block.timestamp < poll.endTime, "Poll ended");

        PollVote storage voterRecord = pollVotes[pollId][msg.sender];
        require(!voterRecord.hasVoted, "Already voted");

        voterRecord.hasVoted = true;
        voterRecord.support = support;
        pollParticipants[pollId]++;

        if (support) {
            poll.votesFor++;
        } else {
            poll.votesAgainst++;
        }

        emit PollVoteCast(pollId, msg.sender, support);
    }

    /**
     * @notice End a poll and calculate results
     * @param pollId Poll ID
     */
    function endPoll(uint256 pollId) external {
        Poll storage poll = polls[pollId];
        require(poll.status == PollStatus.Active, "Poll not active");
        require(block.timestamp >= poll.endTime, "Poll not ended yet");

        poll.status = PollStatus.Ended;
        emit PollEnded(pollId, poll.votesFor, poll.votesAgainst);
    }

    /**
     * @notice Create a proposal from a successful poll (poll-to-proposal pipeline)
     * @dev Requires >30% support in the poll for reduced quorum
     * @param pollId Poll ID to convert
     * @param proposalType Type of proposal to create
     * @param executionData Encoded execution data
     */
    function createProposalFromPoll(
        uint256 pollId,
        ProposalType proposalType,
        bytes memory executionData
    ) external onlyRole(PROPOSER_ROLE) returns (uint256) {
        Poll storage poll = polls[pollId];
        require(poll.status == PollStatus.Ended, "Poll must be ended first");
        require(poll.linkedProposalId == 0, "Already converted");

        // Calculate poll support percentage
        uint256 totalVotes = poll.votesFor + poll.votesAgainst;
        require(totalVotes > 0, "No votes cast");
        uint256 supportPercent = (poll.votesFor * 10000) / totalVotes;
        require(supportPercent >= POLL_PROPOSAL_THRESHOLD, "Insufficient poll support");

        // Require token holdings
        require(
            propertyToken.getVotingPower(poll.propertyId, msg.sender) > 0,
            "Must hold tokens to propose"
        );

        uint256 proposalId = proposalCount++;

        // Apply quorum bonus for poll-backed proposals
        uint256 baseQuorum = _getQuorum(proposalType);
        uint256 adjustedQuorum = baseQuorum > POLL_QUORUM_BONUS 
            ? baseQuorum - POLL_QUORUM_BONUS 
            : baseQuorum;

        // Snapshot voting power
        uint256 snapshotVotingPower = propertyToken.getTotalWeightedVotingPower(poll.propertyId);
        require(snapshotVotingPower > 0, "No voting power exists");
        totalVotingPower[proposalId] = snapshotVotingPower;

        proposals[proposalId] = Proposal({
            id: proposalId,
            propertyId: poll.propertyId,
            proposer: msg.sender,
            proposalType: proposalType,
            title: poll.question,
            description: poll.description,
            ipfsHash: poll.ipfsHash,
            votesFor: 0,
            votesAgainst: 0,
            votesAbstain: 0,
            startTime: block.timestamp,
            endTime: block.timestamp + votingPeriod,
            quorumRequired: adjustedQuorum,
            status: ProposalStatus.Active,
            executionData: executionData
        });

        // Link poll to proposal
        poll.status = PollStatus.ConvertedToProposal;
        poll.linkedProposalId = proposalId;

        emit ProposalCreated(proposalId, poll.propertyId, msg.sender, proposalType, poll.question);
        emit PollConvertedToProposal(pollId, proposalId);

        return proposalId;
    }

    /**
     * @notice Get poll details
     * @param pollId Poll ID
     */
    function getPoll(uint256 pollId) external view returns (Poll memory) {
        return polls[pollId];
    }

    /**
     * @notice Get poll support percentage
     * @param pollId Poll ID
     * @return supportPercent Support in basis points (e.g., 6000 = 60%)
     */
    function getPollSupport(uint256 pollId) external view returns (uint256) {
        Poll storage poll = polls[pollId];
        uint256 totalVotes = poll.votesFor + poll.votesAgainst;
        if (totalVotes == 0) return 0;
        return (poll.votesFor * 10000) / totalVotes;
    }

    /**
     * @notice Get active polls for a property
     * @param propertyId Property ID (0 for platform-wide)
     */
    function getActivePolls(uint256 propertyId) external view returns (Poll[] memory) {
        uint256 count = 0;
        for (uint256 i = 0; i < pollCount; i++) {
            if (polls[i].propertyId == propertyId && polls[i].status == PollStatus.Active) {
                count++;
            }
        }
        Poll[] memory active = new Poll[](count);
        uint256 idx = 0;
        for (uint256 i = 0; i < pollCount; i++) {
            if (polls[i].propertyId == propertyId && polls[i].status == PollStatus.Active) {
                active[idx++] = polls[i];
            }
        }
        return active;
    }

    // ============ SimCity-Style Demand Meter Functions ============

    /**
     * @notice Internal: Update demand meters when a vote is cast
     * @param proposalType The type of proposal being voted on
     * @param weight The voting weight applied
     */
    function _updateDemandMeters(ProposalType proposalType, uint256 weight) internal {
        typeDemandWeights[proposalType] += weight;
        totalDemandWeight += weight;

        // Update snapshot for this type
        if (totalDemandWeight > 0) {
            demandSnapshots[proposalType] = (typeDemandWeights[proposalType] * 10000) / totalDemandWeight;
        }

        emit DemandUpdated(proposalType, typeDemandWeights[proposalType], demandSnapshots[proposalType]);
    }

    /**
     * @notice Get SimCity-style demand bars for all 4 proposal types
     * @return bars Array of 4 values in BPS: [PropertyDev, Treasury, Parameters, Emergency]
     * @dev Like SimCity's R/C/I demand bars - shows what the community wants
     */
    function getDemandBars() external view returns (uint256[4] memory bars) {
        if (totalDemandWeight == 0) return bars;

        for (uint256 i = 0; i < 4; i++) {
            bars[i] = (typeDemandWeights[ProposalType(i)] * 10000) / totalDemandWeight;
        }
        return bars;
    }

    /**
     * @notice Get demand weight for a specific proposal type
     * @param proposalType The proposal type to query
     * @return weight Cumulative vote weight for this type
     * @return bps Demand percentage in basis points
     */
    function getDemandForType(ProposalType proposalType) external view returns (uint256 weight, uint256 bps) {
        weight = typeDemandWeights[proposalType];
        bps = totalDemandWeight > 0 ? (weight * 10000) / totalDemandWeight : 0;
    }

    /**
     * @notice Take a demand snapshot (callable by operator for analytics)
     * @dev Updates all demand snapshots and emits event for off-chain indexing
     */
    function takeDemandSnapshot() external onlyRole(DEFAULT_ADMIN_ROLE) {
        uint256[4] memory bars;
        if (totalDemandWeight > 0) {
            for (uint256 i = 0; i < 4; i++) {
                ProposalType pType = ProposalType(i);
                bars[i] = (typeDemandWeights[pType] * 10000) / totalDemandWeight;
                demandSnapshots[pType] = bars[i];
            }
        }
        emit DemandSnapshotTaken(bars);
    }

    /**
     * @notice Get the effective quorum for a proposal type (includes demand boost)
     * @param proposalType The proposal type
     * @return effectiveQuorum The quorum in basis points after demand adjustments
     */
    function getEffectiveQuorum(ProposalType proposalType) external view returns (uint256) {
        return _getQuorum(proposalType);
    }

    /**
     * @notice Get community health score based on demand diversity and participation
     * @return healthScore Score 0-10000 (higher = healthier community)
     * @dev Measures demand diversity (balanced = healthier) and total participation
     */
    function getCommunityHealthScore() external view returns (uint256 healthScore) {
        if (totalDemandWeight == 0) return 0;

        // Diversity score: How evenly distributed demand is across types
        // Perfect balance = 2500 each = max diversity
        uint256 diversityScore = 0;
        for (uint256 i = 0; i < 4; i++) {
            uint256 typeBps = (typeDemandWeights[ProposalType(i)] * 10000) / totalDemandWeight;
            // Distance from perfect balance (2500)
            uint256 deviation = typeBps > 2500 ? typeBps - 2500 : 2500 - typeBps;
            // Max deviation per type is 2500, so normalize
            diversityScore += (2500 - deviation);
        }
        // diversityScore ranges 0-10000, normalize to 0-5000 (half of health)
        diversityScore = diversityScore / 2;

        // Participation score: Based on total votes cast (capped contribution)
        // More votes = healthier, cap at 5000 for the other half
        uint256 participationScore = totalDemandWeight > 0 ? 5000 : 0;

        healthScore = diversityScore + participationScore;
        if (healthScore > 10000) healthScore = 10000;
    }
}

contracts/PhaseManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@chainlink/contracts/src/v0.8/automation/AutomationCompatible.sol";

interface IPropertyToken {
    enum Phase { County, State, National, International }

    function advancePhase(uint256 propertyId) external;
    function mintTokens(uint256 propertyId, address buyer, uint256 amount) external;
    function getProperty(uint256 propertyId) external view returns (
        uint256 id,
        string memory name,
        string memory uri,
        uint256 totalSupply,
        uint256 mintedSupply,
        uint256 fundingTarget,
        uint256 fundingDeadline,
        uint8 currentPhase,
        bool isActive,
        bool isFunded
    );
    function phaseAllocations(uint256 propertyId, uint8 phase) external view returns (uint256);
    function phaseMinted(uint256 propertyId, uint8 phase) external view returns (uint256);
    function whitelist(address account) external view returns (bool);
}

interface IGovernance {
    function proposalCount() external view returns (uint256);
    function getProposal(uint256 proposalId) external view returns (
        uint256 id,
        uint256 propertyId,
        address proposer,
        uint8 proposalType,
        string memory title,
        string memory description,
        string memory ipfsHash,
        uint256 votesFor,
        uint256 votesAgainst,
        uint256 votesAbstain,
        uint256 startTime,
        uint256 endTime,
        uint256 quorumRequired,
        uint8 status,
        bytes memory executionData
    );
    function getDemandBars() external view returns (uint256[4] memory);
    function getCommunityHealthScore() external view returns (uint256);
}

/**
 * @title RevitaHub Phase Manager
 * @notice Dynamic phase advancement based on engagement analytics
 * @dev Advances phases when 75% engagement threshold OR full subscription is reached
 */
contract PhaseManager is AccessControl, AutomationCompatibleInterface {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    IPropertyToken public propertyToken;
    IGovernance public governance;

    // Engagement threshold for early phase advancement (basis points)
    uint256 public constant ENGAGEMENT_THRESHOLD = 7500; // 75%

    // Minimum engagement period before early advancement (prevents gaming)
    uint256 public constant MIN_ENGAGEMENT_PERIOD = 7 days;

    // Property engagement tracking
    struct PropertyEngagement {
        uint256 propertyId;
        uint256 phaseStartTime;
        uint256 totalEligibleVoters;
        uint256 activeVoters;
        uint256 totalProposals;
        uint256 votedProposals;
        bool isTracking;
    }

    // Engagement metrics per property
    mapping(uint256 => PropertyEngagement) public propertyEngagement;

    // Active properties for automation
    uint256[] public trackedProperties;
    mapping(uint256 => bool) public isTracked;

    // Behavioral nudge triggers
    mapping(uint256 => uint256) public lastNudgeTime;
    uint256 public nudgeCooldown = 24 hours;

    // Engagement bonus tracking (vote-to-earn)
    mapping(uint256 => mapping(address => bool)) public hasClaimed;
    uint256 public constant BONUS_TOKENS = 1; // Tokens awarded for engagement bonus

    // Poll participation bonuses
    mapping(uint256 => mapping(address => bool)) public pollParticipated; // Track poll voters
    mapping(uint256 => uint256) public propertyPollCount; // Number of polls per property
    uint256 public constant POLL_BONUS_MULTIPLIER = 50; // 0.5 extra engagement credit per poll vote (in basis points)

    // Events
    event EngagementUpdated(
        uint256 indexed propertyId,
        uint256 activeVoters,
        uint256 totalEligible,
        uint256 engagementPercent
    );
    event PhaseAdvancedByEngagement(
        uint256 indexed propertyId,
        uint8 fromPhase,
        uint8 toPhase,
        uint256 engagementPercent
    );
    event PhaseAdvancedBySubscription(
        uint256 indexed propertyId,
        uint8 fromPhase,
        uint8 toPhase
    );
    event NudgeTriggered(
        uint256 indexed propertyId,
        string nudgeType,
        uint256 engagementPercent
    );
    event PropertyTrackingStarted(uint256 indexed propertyId);
    event PropertyTrackingStopped(uint256 indexed propertyId);
    event BonusClaimed(uint256 indexed propertyId, address indexed claimer, uint256 bonus);
    event PollParticipationRecorded(uint256 indexed propertyId, address indexed participant);
    event PollBonusApplied(uint256 indexed propertyId, uint256 pollParticipants, uint256 bonusEngagement);
    event DemandNudge(uint256 indexed propertyId, uint8 demandType, uint256 demandBps);
    event DemandDrivenAdvancement(uint256 indexed propertyId, uint256 demandBps);

    constructor(address _propertyToken, address _governance) {
        propertyToken = IPropertyToken(_propertyToken);
        governance = IGovernance(_governance);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(OPERATOR_ROLE, msg.sender);
    }

    /**
     * @notice Start tracking engagement for a property
     * @param propertyId Property ID
     * @param totalEligibleVoters Total number of eligible voters
     */
    function startTracking(uint256 propertyId, uint256 totalEligibleVoters) external onlyRole(OPERATOR_ROLE) {
        require(!isTracked[propertyId], "Already tracking");

        propertyEngagement[propertyId] = PropertyEngagement({
            propertyId: propertyId,
            phaseStartTime: block.timestamp,
            totalEligibleVoters: totalEligibleVoters,
            activeVoters: 0,
            totalProposals: 0,
            votedProposals: 0,
            isTracking: true
        });

        trackedProperties.push(propertyId);
        isTracked[propertyId] = true;

        emit PropertyTrackingStarted(propertyId);
    }

    /**
     * @notice Update engagement metrics for a property
     * @param propertyId Property ID
     * @param activeVoters Number of unique voters
     * @param totalProposals Total proposals for property
     * @param votedProposals Proposals with votes
     */
    function updateEngagement(
        uint256 propertyId,
        uint256 activeVoters,
        uint256 totalProposals,
        uint256 votedProposals
    ) external onlyRole(OPERATOR_ROLE) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");

        engagement.activeVoters = activeVoters;
        engagement.totalProposals = totalProposals;
        engagement.votedProposals = votedProposals;

        uint256 engagementPercent = calculateEngagement(propertyId);
        emit EngagementUpdated(propertyId, activeVoters, engagement.totalEligibleVoters, engagementPercent);

        // Check for nudge triggers
        _checkNudges(propertyId, engagementPercent);

        // Check for early phase advancement
        _checkPhaseAdvancement(propertyId, engagementPercent);
    }

    /**
     * @notice Calculate engagement percentage
     * @param propertyId Property ID
     */
    function calculateEngagement(uint256 propertyId) public view returns (uint256) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        if (engagement.totalEligibleVoters == 0) return 0;

        // Engagement = (active voters / eligible voters) * 100
        // Returns in basis points (e.g., 7500 = 75%)
        return (engagement.activeVoters * 10000) / engagement.totalEligibleVoters;
    }

    /**
     * @notice Check if phase should advance based on engagement
     * @param propertyId Property ID
     * @param engagementPercent Current engagement in basis points
     */
    function _checkPhaseAdvancement(uint256 propertyId, uint256 engagementPercent) internal {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];

        // Check minimum engagement period
        if (block.timestamp < engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD) {
            return;
        }

        // Check engagement threshold
        if (engagementPercent >= ENGAGEMENT_THRESHOLD) {
            _advancePhaseByEngagement(propertyId, engagementPercent);
        }
    }

    /**
     * @notice Advance phase due to high engagement
     * @param propertyId Property ID
     * @param engagementPercent Engagement that triggered advancement
     */
    function _advancePhaseByEngagement(uint256 propertyId, uint256 engagementPercent) internal {
        (,,,,,,,uint8 currentPhase,,) = propertyToken.getProperty(propertyId);

        if (currentPhase < 3) { // Not at International yet
            propertyToken.advancePhase(propertyId);

            // Reset phase tracking
            propertyEngagement[propertyId].phaseStartTime = block.timestamp;
            propertyEngagement[propertyId].activeVoters = 0;

            emit PhaseAdvancedByEngagement(propertyId, currentPhase, currentPhase + 1, engagementPercent);
        }
    }

    /**
     * @notice Check and trigger behavioral nudges
     * @param propertyId Property ID
     * @param engagementPercent Current engagement
     */
    function _checkNudges(uint256 propertyId, uint256 engagementPercent) internal {
        if (block.timestamp < lastNudgeTime[propertyId] + nudgeCooldown) {
            return;
        }

        string memory nudgeType;

        if (engagementPercent < 2500) {
            // Low engagement - urgent nudge
            nudgeType = "urgent_participation";
        } else if (engagementPercent >= 6000 && engagementPercent < 7500) {
            // Near threshold - milestone nudge
            nudgeType = "milestone_near";
        } else if (engagementPercent >= 7000 && engagementPercent < 7500) {
            // Very close - final push nudge
            nudgeType = "phase_closing";
        } else {
            return; // No nudge needed
        }

        lastNudgeTime[propertyId] = block.timestamp;
        emit NudgeTriggered(propertyId, nudgeType, engagementPercent);
    }

    /**
     * @notice Manually trigger phase check (for subscription-based advancement)
     * @param propertyId Property ID
     */
    function checkSubscriptionAdvancement(uint256 propertyId) external {
        (,,,,,,,uint8 currentPhase,,) = propertyToken.getProperty(propertyId);

        uint256 phaseAllocation = propertyToken.phaseAllocations(propertyId, currentPhase);
        uint256 phaseMinted = propertyToken.phaseMinted(propertyId, currentPhase);

        if (phaseMinted >= phaseAllocation && currentPhase < 3) {
            propertyToken.advancePhase(propertyId);

            // Reset tracking for new phase
            propertyEngagement[propertyId].phaseStartTime = block.timestamp;
            propertyEngagement[propertyId].activeVoters = 0;

            emit PhaseAdvancedBySubscription(propertyId, currentPhase, currentPhase + 1);
        }
    }

    // ============ Chainlink Automation ============

    /**
     * @notice Chainlink Automation check
     */
    function checkUpkeep(bytes calldata) external view override returns (bool upkeepNeeded, bytes memory performData) {
        for (uint256 i = 0; i < trackedProperties.length; i++) {
            uint256 propertyId = trackedProperties[i];
            PropertyEngagement storage engagement = propertyEngagement[propertyId];

            if (!engagement.isTracking) continue;

            // Check if minimum period passed
            if (block.timestamp < engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD) continue;

            uint256 engagementPercent = calculateEngagement(propertyId);

            if (engagementPercent >= ENGAGEMENT_THRESHOLD) {
                return (true, abi.encode(propertyId, engagementPercent));
            }
        }
        return (false, "");
    }

    /**
     * @notice Chainlink Automation perform
     */
    function performUpkeep(bytes calldata performData) external override {
        (uint256 propertyId, ) = abi.decode(performData, (uint256, uint256));

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");
        require(block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD, "Too early");

        // Re-verify engagement
        uint256 currentEngagement = calculateEngagement(propertyId);
        require(currentEngagement >= ENGAGEMENT_THRESHOLD, "Threshold not met");

        _advancePhaseByEngagement(propertyId, currentEngagement);
    }

    /**
     * @notice Stop tracking a property
     * @param propertyId Property ID
     */
    function stopTracking(uint256 propertyId) external onlyRole(OPERATOR_ROLE) {
        require(isTracked[propertyId], "Not tracking");

        propertyEngagement[propertyId].isTracking = false;
        isTracked[propertyId] = false;

        emit PropertyTrackingStopped(propertyId);
    }

    /**
     * @notice Update nudge cooldown
     * @param newCooldown New cooldown in seconds
     */
    function setNudgeCooldown(uint256 newCooldown) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newCooldown >= 1 hours && newCooldown <= 7 days, "Invalid cooldown");
        nudgeCooldown = newCooldown;
    }

    /**
     * @notice Get all tracked properties
     */
    function getTrackedProperties() external view returns (uint256[] memory) {
        return trackedProperties;
    }

    /**
     * @notice Claim engagement bonus when threshold is met (vote-to-earn)
     * @dev Mints bonus tokens to active participants when 75% engagement is reached
     * @param propertyId Property ID
     */
    function claimEngagementBonus(uint256 propertyId) external {
        require(propertyToken.whitelist(msg.sender), "Not whitelisted");
        require(!hasClaimed[propertyId][msg.sender], "Already claimed");

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");
        require(calculateEngagement(propertyId) >= ENGAGEMENT_THRESHOLD, "Threshold not met");
        require(block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD, "Too early");

        // Mark as claimed before minting (reentrancy protection)
        hasClaimed[propertyId][msg.sender] = true;

        // Mint bonus tokens (requires MINTER_ROLE granted to PhaseManager)
        propertyToken.mintTokens(propertyId, msg.sender, BONUS_TOKENS);

        emit BonusClaimed(propertyId, msg.sender, BONUS_TOKENS);
    }

    /**
     * @notice Get engagement details for a property
     * @param propertyId Property ID
     */
    function getEngagement(uint256 propertyId) external view returns (
        uint256 phaseStartTime,
        uint256 totalEligible,
        uint256 activeVoters,
        uint256 engagementPercent,
        bool isTracking
    ) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        return (
            engagement.phaseStartTime,
            engagement.totalEligibleVoters,
            engagement.activeVoters,
            calculateEngagement(propertyId),
            engagement.isTracking
        );
    }

    // ============ Poll Bonus Functions ============

    /**
     * @notice Record poll participation for engagement bonus credit
     * @dev Called by operator when user votes on a property-related poll
     * @param propertyId Property ID
     * @param participant Address of poll participant
     */
    function recordPollParticipation(
        uint256 propertyId,
        address participant
    ) external onlyRole(OPERATOR_ROLE) {
        require(isTracked[propertyId], "Property not tracked");
        require(!pollParticipated[propertyId][participant], "Already recorded");

        pollParticipated[propertyId][participant] = true;
        emit PollParticipationRecorded(propertyId, participant);
    }

    /**
     * @notice Update engagement with poll participation bonus
     * @dev Adds half-credit for poll voters to boost engagement calculation
     * @param propertyId Property ID
     * @param activeVoters Number of unique proposal voters
     * @param totalProposals Total proposals for property
     * @param votedProposals Proposals with votes
     * @param pollParticipants Number of unique poll voters
     */
    function updateEngagementWithPolls(
        uint256 propertyId,
        uint256 activeVoters,
        uint256 totalProposals,
        uint256 votedProposals,
        uint256 pollParticipants
    ) external onlyRole(OPERATOR_ROLE) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");

        // Calculate poll bonus: half credit per poll voter
        // pollParticipants / 2 added to active voters (but not exceeding totalEligible)
        uint256 pollBonus = (pollParticipants * POLL_BONUS_MULTIPLIER) / 100;
        uint256 adjustedActiveVoters = activeVoters + pollBonus;

        // Cap at total eligible voters
        if (adjustedActiveVoters > engagement.totalEligibleVoters) {
            adjustedActiveVoters = engagement.totalEligibleVoters;
        }

        engagement.activeVoters = adjustedActiveVoters;
        engagement.totalProposals = totalProposals;
        engagement.votedProposals = votedProposals;

        uint256 engagementPercent = calculateEngagement(propertyId);
        emit EngagementUpdated(propertyId, adjustedActiveVoters, engagement.totalEligibleVoters, engagementPercent);
        emit PollBonusApplied(propertyId, pollParticipants, pollBonus);

        // Check for nudge triggers
        _checkNudges(propertyId, engagementPercent);

        // Check for early phase advancement
        _checkPhaseAdvancement(propertyId, engagementPercent);
    }

    /**
     * @notice Claim poll-boosted engagement bonus
     * @dev Extra bonus tokens for poll participants when threshold met
     * @param propertyId Property ID
     */
    function claimPollBoostBonus(uint256 propertyId) external {
        require(propertyToken.whitelist(msg.sender), "Not whitelisted");
        require(pollParticipated[propertyId][msg.sender], "Did not participate in polls");
        require(!hasClaimed[propertyId][msg.sender], "Already claimed");

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");
        require(calculateEngagement(propertyId) >= ENGAGEMENT_THRESHOLD, "Threshold not met");
        require(block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD, "Too early");

        hasClaimed[propertyId][msg.sender] = true;

        // Poll participants get 2x bonus
        uint256 bonusAmount = BONUS_TOKENS * 2;
        propertyToken.mintTokens(propertyId, msg.sender, bonusAmount);

        emit BonusClaimed(propertyId, msg.sender, bonusAmount);
    }

    /**
     * @notice Check if user participated in polls for a property
     * @param propertyId Property ID
     * @param participant User address
     */
    function hasParticipatedInPolls(uint256 propertyId, address participant) external view returns (bool) {
        return pollParticipated[propertyId][participant];
    }

    // ============ Demand-Driven Engagement (SimCity Integration) ============

    /**
     * @notice Update engagement based on governance demand signals
     * @dev Reads demand bars from Governance contract, triggers phase advancement
     *      if PropertyDevelopment demand exceeds threshold. Like SimCity's advisor system.
     * @param propertyId Property ID to evaluate
     */
    function updateDemandEngagement(uint256 propertyId) external onlyRole(OPERATOR_ROLE) {
        require(isTracked[propertyId], "Property not tracked");
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");

        // Get demand bars from Governance (SimCity-style RCI readings)
        uint256[4] memory demandBars = governance.getDemandBars();
        uint256 propDemandBps = demandBars[0]; // PropertyDevelopment = index 0

        // Emit advisor-style nudge for UI
        emit DemandNudge(propertyId, 0, propDemandBps);

        // Check if PropertyDevelopment demand meets engagement threshold
        if (propDemandBps >= ENGAGEMENT_THRESHOLD && 
            block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD) {
            _advancePhaseByEngagement(propertyId, propDemandBps);
            emit DemandDrivenAdvancement(propertyId, propDemandBps);
        }
    }

    /**
     * @notice Get community health from governance contract
     * @return healthScore 0-10000 based on demand diversity and participation
     */
    function getCommunityHealth() external view returns (uint256) {
        return governance.getCommunityHealthScore();
    }

    /**
     * @notice Get demand-adjusted engagement metrics for a property
     * @param propertyId Property ID
     * @return baseEngagement Standard engagement percentage in BPS
     * @return demandBars Governance demand bars [PropDev, Treasury, Params, Emergency]
     * @return healthScore Community health score 0-10000
     * @return isReadyForAdvancement Whether demand conditions support phase advancement
     */
    function getDemandEngagementMetrics(uint256 propertyId) external view returns (
        uint256 baseEngagement,
        uint256[4] memory demandBars,
        uint256 healthScore,
        bool isReadyForAdvancement
    ) {
        baseEngagement = calculateEngagement(propertyId);
        demandBars = governance.getDemandBars();
        healthScore = governance.getCommunityHealthScore();

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        isReadyForAdvancement = engagement.isTracking && 
            demandBars[0] >= ENGAGEMENT_THRESHOLD &&
            block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD;
    }
}

